import React, { useState } from 'react';
import Barcode from 'react-barcode';
import { BiPrinter } from 'react-icons/bi';
import { useParams } from 'react-router-dom';
import s from './code-print.module.scss';   // SCSS-модуль

const CodePrint = () => {
  const { code = '', name = '', price = '' } = useParams();
  const [qty, setQty] = useState(1);

  const labels = Array.from({ length: qty || 1 });

  return (
    // id нужен, чтобы в @media print «показать только этот блок»
    <div id="printWrapper" className={s.wrapper}>
      {labels.map((_, i) => (
        <div key={i} className={s.label}>
          <h3 className={s.title}>{name}</h3>
          <p className={s.price}>Стоимость: {price}&nbsp;сом</p>

          {/* SVG устойчивее в режиме печати, чем canvas */}
          <Barcode
            value={code}
            renderer="svg"
            width={1.4}
            height={45}
            fontSize={14}
            margin={0}
            className={s.barcode}
          />
        </div>
      ))}

      {/* Панель управления (не печатается) */}
      <div className={s.controls}>
        <input
          type="number"
          min="1"
          value={qty}
          onChange={e => setQty(Math.max(+e.target.value, 1))}
        />
        <button onClick={() => window.print()}>
          Распечатать&nbsp;<BiPrinter size={18} />
        </button>
      </div>
    </div>
  );
};

export default CodePrint;
